2035→    /** A position-aware collection to ensure consistency between the position of items and the collection  */
2036→    class CardCollection<T : PositionAware?> : Iterable<T> {
2037→        var wrapped: MutableList<T> = ArrayList(0)
2038→            private set
2039→        fun size(): Int {
2040→            return wrapped.size
2041→        }
2042→
2043→        operator fun get(index: Int): T {
2044→            return wrapped[index]
2045→        }
2046→
2047→        fun reset() {
2048→            wrapped = ArrayList(0)
2049→        }
2050→
2051→        fun replaceWith(value: MutableList<T>) {
2052→            wrapped = value
2053→        }
2054→
2055→        fun reverse() {
2056→            wrapped.reverse()
2057→            wrapped.forEachIndexed { pos, card -> card!!.position = pos }
2058→        }
2059→
2060→        override fun iterator(): MutableIterator<T> {
2061→            return wrapped.iterator()
2062→        }
2063→
2064→        fun clear() {
2065→            wrapped.clear()
2066→        }
2067→    }
