2211→        private fun updateSearchItemQA() {
2212→            if (mQa != null) {
2213→                return
2214→            }
2215→            // render question and answer
2216→            val qa = card.renderOutput(reload = true, browser = true)
2217→            // Render full question / answer if the bafmt (i.e. "browser appearance") setting forced blank result
2218→            if (qa.questionText.isEmpty() || qa.answerText.isEmpty()) {
2219→                val (question_text, answer_text) = card.renderOutput(
2220→                    reload = true,
2221→                    browser = false
2222→                )
2223→                if (qa.questionText.isEmpty()) {
2224→                    qa.questionText = question_text
2225→                }
2226→                if (qa.answerText.isEmpty()) {
2227→                    qa.answerText = answer_text
2228→                }
2229→            }
2230→            // update the original hash map to include rendered question & answer
2231→            var q = qa.questionText
2232→            var a = qa.answerText
2233→            // remove the question from the start of the answer if it exists
2234→            if (a.startsWith(q)) {
