    @VisibleForTesting
    fun repositionCardsNoValidation(cardIds: List<CardId>, position: Int) {
        launchCatchingTask {
            val changes = withProgress {
                undoableOp {
                    sched.sortCards(cardIds, position, 1, false, true)
                }
            }
            val count = changes.count
            showSnackbar(
                resources.getQuantityString(
