2054→
2055→        fun reverse() {
2056→            wrapped.reverse()
2057→            wrapped.forEachIndexed { pos, card -> card!!.position = pos }
2058→        }
2059→
2060→        override fun iterator(): MutableIterator<T> {
2061→            return wrapped.iterator()
2062→        }
2063→
2064→        fun clear() {
2065→            wrapped.clear()
